'use client';

import { useQuery } from '@tanstack/react-query';
import { createClient } from '@/lib/supabase/client';
import { useUserProfile } from './useUserProfile';
import { useFinancialAccounts } from './useFinancialAccounts';
import {
    FinancialMetrics,
    MonthlyData,
    CategoryExpense,
    CostBreakdown,
} from '@/types/financial';
import { format, startOfMonth, endOfMonth, subMonths } from 'date-fns';
import { ptBR } from 'date-fns/locale';

interface UseFinancialMetricsOptions {
    year?: number;
    month?: number;
    startDate?: Date;
    endDate?: Date;
}

export function useFinancialMetrics(options: UseFinancialMetricsOptions = {}) {
    const supabase = createClient();
    const { user, isSecretaria } = useUserProfile();
    const { accounts, totalBalance } = useFinancialAccounts();

    const currentDate = new Date();
    const year = options.year || currentDate.getFullYear();
    const month = options.month || currentDate.getMonth() + 1;

    // Current month metrics
    const {
        data: metrics,
        isLoading: isLoadingMetrics,
        error: metricsError,
    } = useQuery({
        queryKey: ['financial-metrics', user?.id, year, month, isSecretaria],
        staleTime: 5 * 60 * 1000, // 5 minutos
        gcTime: 10 * 60 * 1000,   // 10 minutos
        queryFn: async (): Promise<FinancialMetrics> => {
            if (!user?.id || accounts.length === 0) {
                return {
                    totalBalance: 0,
                    monthRevenue: 0,
                    monthExpenses: 0,
                    monthProfit: 0,
                    monthTotalCosts: 0,
                    monthNetProfit: 0,
                    netProfitMargin: 0,
                };
            }

            const accountIds = accounts.map((a) => a.id);
            const startDate = `${year}-${String(month).padStart(2, '0')}-01`;
            const endDate = format(endOfMonth(new Date(year, month - 1)), 'yyyy-MM-dd');

            // Get month transactions
            const { data: transactions } = await supabase
                .from('financial_transactions')
                .select('amount, type, status')
                .in('account_id', accountIds)
                .gte('transaction_date', startDate)
                .lte('transaction_date', endDate)
                .eq('status', 'completed') as { data: { amount: number | null; type: string; status: string }[] | null };

            // Get costs for the month
            const { data: costs } = await supabase
                .from('transaction_costs')
                .select('amount, transaction_id')
                .gte('created_at', startDate)
                .lte('created_at', endDate) as { data: { amount: number | null; transaction_id: string }[] | null };

            const monthRevenue = (transactions || [])
                .filter((t) => t.type === 'entrada')
                .reduce((sum, t) => sum + (t.amount || 0), 0);

            const monthExpenses = (transactions || [])
                .filter((t) => t.type === 'saida')
                .reduce((sum, t) => sum + (t.amount || 0), 0);

            const monthTotalCosts = (costs || []).reduce((sum, c) => sum + (c.amount || 0), 0);
            const monthProfit = monthRevenue - monthExpenses;
            const monthNetProfit = monthProfit - monthTotalCosts;
            const netProfitMargin = monthRevenue > 0 ? (monthNetProfit / monthRevenue) * 100 : 0;

            return {
                totalBalance,
                monthRevenue,
                monthExpenses,
                monthProfit,
                profitMargin: monthRevenue > 0 ? (monthProfit / monthRevenue) * 100 : 0,
                totalAccounts: accounts.length,
                monthTotalCosts,
                monthNetProfit,
                netProfitMargin,
            };
        },
        enabled: !!user?.id && accounts.length > 0,
    });

    // Monthly data for charts (last 6 months) - OTIMIZADO: query única
    const { data: monthlyData = [], isLoading: isLoadingMonthly } = useQuery({
        queryKey: ['financial-monthly-data', user?.id, isSecretaria],
        staleTime: 5 * 60 * 1000, // 5 minutos
        gcTime: 10 * 60 * 1000,   // 10 minutos
        queryFn: async (): Promise<MonthlyData[]> => {
            if (!user?.id || accounts.length === 0) return [];

            const accountIds = accounts.map((a) => a.id);

            // Query única para todos os 6 meses
            const sixMonthsAgo = format(startOfMonth(subMonths(currentDate, 5)), 'yyyy-MM-dd');
            const today = format(endOfMonth(currentDate), 'yyyy-MM-dd');

            const { data: transactions } = await supabase
                .from('financial_transactions')
                .select('amount, type, transaction_date')
                .in('account_id', accountIds)
                .gte('transaction_date', sixMonthsAgo)
                .lte('transaction_date', today)
                .eq('status', 'completed') as { data: { amount: number | null; type: string; transaction_date: string }[] | null };

            // Agrupar por mês no JavaScript
            const monthlyMap = new Map<string, { receitas: number; despesas: number }>();

            // Inicializar os 6 meses
            for (let i = 5; i >= 0; i--) {
                const date = subMonths(currentDate, i);
                const key = format(date, 'yyyy-MM');
                monthlyMap.set(key, { receitas: 0, despesas: 0 });
            }

            // Agregar transações
            (transactions || []).forEach((t) => {
                const key = t.transaction_date.substring(0, 7); // 'yyyy-MM'
                const existing = monthlyMap.get(key);
                if (existing) {
                    if (t.type === 'entrada') {
                        existing.receitas += t.amount || 0;
                    } else {
                        existing.despesas += t.amount || 0;
                    }
                }
            });

            // Converter para array ordenado
            const data: MonthlyData[] = [];
            for (let i = 5; i >= 0; i--) {
                const date = subMonths(currentDate, i);
                const key = format(date, 'yyyy-MM');
                const monthLabel = format(date, 'MMM', { locale: ptBR });
                const values = monthlyMap.get(key) || { receitas: 0, despesas: 0 };

                data.push({
                    month: monthLabel.charAt(0).toUpperCase() + monthLabel.slice(1),
                    receitas: values.receitas,
                    despesas: values.despesas,
                    lucro: values.receitas - values.despesas,
                });
            }

            return data;
        },
        enabled: !!user?.id && accounts.length > 0,
    });

    // Category expenses breakdown
    const { data: categoryExpenses = [], isLoading: isLoadingCategories } = useQuery({
        queryKey: ['financial-category-expenses', user?.id, year, month, isSecretaria],
        staleTime: 5 * 60 * 1000, // 5 minutos
        gcTime: 10 * 60 * 1000,   // 10 minutos
        queryFn: async (): Promise<CategoryExpense[]> => {
            if (!user?.id || accounts.length === 0) return [];

            const accountIds = accounts.map((a) => a.id);
            const startDate = `${year}-${String(month).padStart(2, '0')}-01`;
            const endDate = format(endOfMonth(new Date(year, month - 1)), 'yyyy-MM-dd');

            const { data: transactions } = await supabase
                .from('financial_transactions')
                .select(`
                    amount,
                    category:financial_categories(id, name, color)
                `)
                .in('account_id', accountIds)
                .eq('type', 'saida')
                .eq('status', 'completed')
                .gte('transaction_date', startDate)
                .lte('transaction_date', endDate);

            // Group by category
            const categoryMap = new Map<string, { name: string; value: number; color: string }>();

            (transactions || []).forEach((t: { amount: number | null; category: { id: string; name: string; color: string | null } | null }) => {
                const categoryId = t.category?.id || 'uncategorized';
                const categoryName = t.category?.name || 'Sem categoria';
                const categoryColor = t.category?.color || '#9ca3af';

                if (!categoryMap.has(categoryId)) {
                    categoryMap.set(categoryId, {
                        name: categoryName,
                        value: 0,
                        color: categoryColor,
                    });
                }

                const current = categoryMap.get(categoryId)!;
                current.value += t.amount || 0;
            });

            const total = Array.from(categoryMap.values()).reduce((sum, c) => sum + c.value, 0);

            return Array.from(categoryMap.values())
                .map((c) => ({
                    ...c,
                    percentage: total > 0 ? (c.value / total) * 100 : 0,
                }))
                .sort((a, b) => b.value - a.value);
        },
        enabled: !!user?.id && accounts.length > 0,
    });

    // Cost breakdown
    const { data: costBreakdown = [], isLoading: isLoadingCosts } = useQuery({
        queryKey: ['financial-cost-breakdown', user?.id, year, month, isSecretaria],
        staleTime: 5 * 60 * 1000, // 5 minutos
        gcTime: 10 * 60 * 1000,   // 10 minutos
        queryFn: async (): Promise<CostBreakdown[]> => {
            if (!user?.id) return [];

            const startDate = `${year}-${String(month).padStart(2, '0')}-01`;
            const endDate = format(endOfMonth(new Date(year, month - 1)), 'yyyy-MM-dd');

            const { data: costs } = await supabase
                .from('transaction_costs')
                .select('amount, cost_type')
                .gte('created_at', startDate)
                .lte('created_at', endDate) as { data: { amount: number | null; cost_type: string | null }[] | null };

            // Group by cost type
            const typeMap = new Map<string, number>();
            const typeColors: Record<string, string> = {
                taxa_cartao: '#ef4444',
                imposto: '#f97316',
                comissao: '#eab308',
                taxa_bancaria: '#22c55e',
                outros: '#9ca3af',
            };

            const typeNames: Record<string, string> = {
                taxa_cartao: 'Taxa de Cartão',
                imposto: 'Impostos',
                comissao: 'Comissões',
                taxa_bancaria: 'Taxas Bancárias',
                outros: 'Outros',
            };

            (costs || []).forEach((c) => {
                const type = c.cost_type || 'outros';
                typeMap.set(type, (typeMap.get(type) || 0) + (c.amount || 0));
            });

            const total = Array.from(typeMap.values()).reduce((sum, v) => sum + v, 0);

            return Array.from(typeMap.entries())
                .map(([type, value]) => ({
                    type: type as CostBreakdown['type'],
                    name: typeNames[type] || type,
                    value,
                    color: typeColors[type] || '#9ca3af',
                    percentage: total > 0 ? (value / total) * 100 : 0,
                }))
                .sort((a, b) => b.value - a.value);
        },
        enabled: !!user?.id,
    });

    // Generate cash flow projection (current + 2 months ahead)
    const cashFlowProjection = monthlyData.map((m, i) => ({
        month: m.month,
        saldo: monthlyData.slice(0, i + 1).reduce((sum, d) => sum + d.lucro, metrics?.totalBalance || 0),
        projected: false,
    }));

    // Add 2 months of projection
    if (cashFlowProjection.length > 0) {
        const lastSaldo = cashFlowProjection[cashFlowProjection.length - 1]?.saldo || 0;
        const avgLucro = monthlyData.reduce((sum, m) => sum + m.lucro, 0) / Math.max(monthlyData.length, 1);

        const nextMonths = ['Fev', 'Mar', 'Abr', 'Mai', 'Jun', 'Jul', 'Ago', 'Set', 'Out', 'Nov', 'Dez', 'Jan'];
        const currentMonthIndex = currentDate.getMonth();

        for (let i = 1; i <= 2; i++) {
            const nextMonthName = nextMonths[(currentMonthIndex + i) % 12];
            cashFlowProjection.push({
                month: nextMonthName,
                saldo: lastSaldo + (avgLucro * i),
                projected: true,
            });
        }
    }

    return {
        metrics: metrics || {
            totalBalance: 0,
            monthRevenue: 0,
            monthExpenses: 0,
            monthProfit: 0,
            monthTotalCosts: 0,
            monthNetProfit: 0,
            netProfitMargin: 0,
        },
        monthlyData,
        categoryExpenses,
        costBreakdown,
        // Aliases for compatibility with Financial client
        expensesByCategory: categoryExpenses,
        costsBreakdown: costBreakdown,
        cashFlowProjection,
        isLoading: isLoadingMetrics || isLoadingMonthly || isLoadingCategories || isLoadingCosts,
        metricsError,
    };
}
