'use client';

import { Card, CardContent, CardDescription, CardHeader, CardTitle } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { ArrowLeft, BarChart3, Download, TrendingUp, TrendingDown, DollarSign, PieChart, Loader2 } from "lucide-react";
import { useRouter } from "next/navigation";
import { useFinancialMetrics } from "@/hooks/useFinancialMetrics";
import { formatCurrency } from "@/lib/utils";

export default function FinancialReportsPage() {
    const router = useRouter();
    const { metrics, monthlyData, categoryExpenses, isLoading } = useFinancialMetrics();

    if (isLoading) {
        return (
            <div className="flex items-center justify-center h-64">
                <Loader2 className="h-8 w-8 animate-spin text-pink-500" />
            </div>
        );
    }

    return (
        <div className="space-y-6">
            {/* Header */}
            <div className="flex items-center justify-between">
                <div className="flex items-center gap-4">
                    <Button variant="ghost" size="icon" onClick={() => router.push('/financial')}>
                        <ArrowLeft className="h-5 w-5" />
                    </Button>
                    <div>
                        <h1 className="text-2xl font-bold text-foreground flex items-center gap-2">
                            <BarChart3 className="h-6 w-6 text-pink-500" />
                            Relatórios Financeiros
                        </h1>
                        <p className="text-muted-foreground">Análises detalhadas das suas finanças</p>
                    </div>
                </div>
                <Button variant="outline" className="gap-2">
                    <Download className="h-4 w-4" />
                    Exportar PDF
                </Button>
            </div>

            {/* Summary Cards */}
            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-4">
                <Card className="bg-gradient-to-br from-emerald-500/10 to-transparent border-emerald-500/20">
                    <CardContent className="p-6">
                        <div className="flex items-center justify-between mb-2">
                            <p className="text-sm text-muted-foreground">Total Receitas</p>
                            <TrendingUp className="w-5 h-5 text-emerald-500" />
                        </div>
                        <p className="text-2xl font-bold text-emerald-500">{formatCurrency(metrics.monthRevenue)}</p>
                    </CardContent>
                </Card>

                <Card className="bg-gradient-to-br from-red-500/10 to-transparent border-red-500/20">
                    <CardContent className="p-6">
                        <div className="flex items-center justify-between mb-2">
                            <p className="text-sm text-muted-foreground">Total Despesas</p>
                            <TrendingDown className="w-5 h-5 text-red-500" />
                        </div>
                        <p className="text-2xl font-bold text-red-500">{formatCurrency(metrics.monthExpenses)}</p>
                    </CardContent>
                </Card>

                <Card className="bg-gradient-to-br from-blue-500/10 to-transparent border-blue-500/20">
                    <CardContent className="p-6">
                        <div className="flex items-center justify-between mb-2">
                            <p className="text-sm text-muted-foreground">Lucro Líquido</p>
                            <DollarSign className="w-5 h-5 text-blue-500" />
                        </div>
                        <p className="text-2xl font-bold text-blue-500">{formatCurrency(metrics.monthNetProfit)}</p>
                    </CardContent>
                </Card>

                <Card className="bg-gradient-to-br from-purple-500/10 to-transparent border-purple-500/20">
                    <CardContent className="p-6">
                        <div className="flex items-center justify-between mb-2">
                            <p className="text-sm text-muted-foreground">Margem de Lucro</p>
                            <PieChart className="w-5 h-5 text-purple-500" />
                        </div>
                        <p className="text-2xl font-bold text-purple-500">{metrics.netProfitMargin.toFixed(1)}%</p>
                    </CardContent>
                </Card>
            </div>

            {/* Monthly Data Table */}
            <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
                <Card>
                    <CardHeader>
                        <CardTitle>Evolução Mensal</CardTitle>
                        <CardDescription>Receitas vs Despesas ao longo do tempo</CardDescription>
                    </CardHeader>
                    <CardContent>
                        <div className="space-y-3">
                            {monthlyData.map((month, index) => (
                                <div key={index} className="flex items-center justify-between p-3 bg-muted/30 rounded-lg">
                                    <span className="font-medium">{month.month}</span>
                                    <div className="flex gap-4 text-sm">
                                        <span className="text-emerald-500">+{formatCurrency(month.receitas)}</span>
                                        <span className="text-red-500">-{formatCurrency(month.despesas)}</span>
                                        <span className={month.lucro >= 0 ? "text-blue-500" : "text-red-500"}>
                                            {formatCurrency(month.lucro)}
                                        </span>
                                    </div>
                                </div>
                            ))}
                        </div>
                    </CardContent>
                </Card>

                <Card>
                    <CardHeader>
                        <CardTitle>Despesas por Categoria</CardTitle>
                        <CardDescription>Distribuição das despesas</CardDescription>
                    </CardHeader>
                    <CardContent>
                        <div className="space-y-3">
                            {categoryExpenses.length === 0 ? (
                                <p className="text-muted-foreground text-center py-4">
                                    Nenhuma despesa registrada no período
                                </p>
                            ) : (
                                categoryExpenses.map((category, index) => (
                                    <div key={index} className="flex items-center justify-between p-3 bg-muted/30 rounded-lg">
                                        <div className="flex items-center gap-2">
                                            <div
                                                className="w-3 h-3 rounded-full"
                                                style={{ backgroundColor: category.color }}
                                            />
                                            <span className="font-medium">{category.name}</span>
                                        </div>
                                        <div className="flex gap-4 text-sm">
                                            <span className="text-muted-foreground">{category.percentage.toFixed(1)}%</span>
                                            <span className="font-medium">{formatCurrency(category.value)}</span>
                                        </div>
                                    </div>
                                ))
                            )}
                        </div>
                    </CardContent>
                </Card>
            </div>
        </div>
    );
}
