'use client';

import { useQuery, useMutation, useQueryClient } from '@tanstack/react-query';
import { createClient } from '@/lib/supabase/client';
import { useUserProfile } from './useUserProfile';
import { toast } from '@/hooks/use-toast';
import {
    FinancialAccount,
    FinancialAccountInsert,
    FinancialAccountUpdate,
    FinancialAccountWithBalance,
} from '@/types/financial';

export function useFinancialAccounts() {
    const supabase = createClient();
    const queryClient = useQueryClient();
    const { user, profile, isSecretaria } = useUserProfile();

    // Query for accounts - secretaries see linked doctors' accounts
    const {
        data: accounts = [],
        isLoading,
        error,
        refetch,
    } = useQuery({
        queryKey: ['financial-accounts', user?.id, isSecretaria],
        queryFn: async (): Promise<FinancialAccountWithBalance[]> => {
            if (!user?.id) return [];

            let query = supabase
                .from('financial_accounts')
                .select('*')
                .eq('is_active', true)
                .order('name');

            // Secretaries: get accounts from linked doctors
            if (isSecretaria) {
                const { data: links } = await supabase
                    .from('secretary_doctor_links')
                    .select('doctor_id')
                    .eq('secretary_id', user.id) as { data: { doctor_id: string }[] | null };

                if (links && links.length > 0) {
                    const doctorIds = links.map((l) => l.doctor_id);
                    query = query.in('user_id', doctorIds);
                } else {
                    return [];
                }
            }

            const { data, error } = await query;

            if (error) {
                console.error('Error fetching accounts:', error);
                throw error;
            }

            return (data || []) as FinancialAccountWithBalance[];
        },
        enabled: !!user?.id,
    });

    // Create account mutation
    const createAccount = useMutation({
        mutationFn: async (newAccount: Omit<FinancialAccountInsert, 'user_id' | 'organization_id'>) => {
            if (!user?.id) throw new Error('User not authenticated');

            const accountData: FinancialAccountInsert = {
                ...newAccount,
                user_id: user.id,
                organization_id: profile?.organization_id || null,
            };

            const { data, error } = await supabase
                .from('financial_accounts')
                .insert(accountData as never)
                .select()
                .single();

            if (error) throw error;
            return data as FinancialAccount;
        },
        onSuccess: () => {
            queryClient.invalidateQueries({ queryKey: ['financial-accounts'] });
            toast({
                title: 'Conta criada',
                description: 'A conta bancária foi criada com sucesso.',
            });
        },
        onError: (error: Error) => {
            console.error('Error creating account:', error);
            toast({
                title: 'Erro ao criar conta',
                description: error.message,
                variant: 'destructive',
            });
        },
    });

    // Update account mutation
    const updateAccount = useMutation({
        mutationFn: async ({
            id,
            updates,
        }: {
            id: string;
            updates: FinancialAccountUpdate;
        }) => {
            const { data, error } = await supabase
                .from('financial_accounts')
                .update(updates as never)
                .eq('id', id)
                .select()
                .single();

            if (error) throw error;
            return data as FinancialAccount;
        },
        onSuccess: () => {
            queryClient.invalidateQueries({ queryKey: ['financial-accounts'] });
            toast({
                title: 'Conta atualizada',
                description: 'A conta bancária foi atualizada com sucesso.',
            });
        },
        onError: (error: Error) => {
            console.error('Error updating account:', error);
            toast({
                title: 'Erro ao atualizar conta',
                description: error.message,
                variant: 'destructive',
            });
        },
    });

    // Delete account mutation (soft delete)
    const deleteAccount = useMutation({
        mutationFn: async (id: string) => {
            const { error } = await supabase
                .from('financial_accounts')
                .update({ is_active: false } as never)
                .eq('id', id);

            if (error) throw error;
        },
        onSuccess: () => {
            queryClient.invalidateQueries({ queryKey: ['financial-accounts'] });
            toast({
                title: 'Conta removida',
                description: 'A conta bancária foi removida com sucesso.',
            });
        },
        onError: (error: Error) => {
            console.error('Error deleting account:', error);
            toast({
                title: 'Erro ao remover conta',
                description: error.message,
                variant: 'destructive',
            });
        },
    });

    // Calculate total balance
    const totalBalance = accounts.reduce(
        (sum, account) => sum + (account.balance || 0),
        0
    );

    // Get default account
    const defaultAccount = accounts.find((a) => a.is_default) || accounts[0];

    return {
        accounts,
        isLoading,
        error,
        refetch,
        createAccount,
        updateAccount,
        deleteAccount,
        totalBalance,
        defaultAccount,
    };
}
